class Solution:
    def maxRotateFunction(self, nums: List[int]) -> int:
        n = len(nums)
        s = sum(nums)
        f = sum(i * nums[i] for i in range(n))
        ans = f
        for k in range(1, n):
            f = f + s - n * nums[n - k]
            ans = max(ans, f)
        return ans

