int maxRotateFunction(int* nums, int n) {
    long long sum = 0, f = 0;
    for (int i = 0; i < n; i++) { sum += nums[i]; f += (long long)i * nums[i]; }
    long long ans = f;
    for (int k = 1; k < n; k++) {
        f = f + sum - (long long)n * nums[n - k];
        if (f > ans) ans = f;
    }
    return (int)ans;
}
